    <script>
        function submitSingleDelete(id) {
            if (confirm('Move this message to trash?')) {
                $('#singleDeleteId').val(id);
                $('#singleDeleteForm').submit();
            }
        }

        $(document).on('click', '.preview-trigger', function () {
            $('#fullViewImage').attr('src', $(this).attr('src'));
            new bootstrap.Modal(document.getElementById('imageModal')).show();
        });

        $('#selectAll').click(function () {
            $('.msg-checkbox').prop('checked', this.checked);
            toggleBulkBtn();
        });

        $(document).on('change', '.msg-checkbox', toggleBulkBtn);

        function toggleBulkBtn() {
            const count = $('.msg-checkbox:checked').length;
            if (count > 0) {
                $('#bulkDeleteBtn').fadeIn().find('span').text(`(${count})`);
            } else {
                $('#bulkDeleteBtn').fadeOut();
            }
        }

        function handleBu");
                WriteLiteral(@"lkDelete() {
            if (confirm(`Delete ${$('.msg-checkbox:checked').length} messages?`)) {
                $('#bulkDeleteForm').submit();
            }
        }

        function viewMessage(id) {
            $('.drawer-body').scrollTop(0);
            $.get('/Contact/GetMessageDetails/' + id, function (data) {
                $('#d_name').text(data.fullName);
                $('#d_email').text(data.email);
                $('#d_body').text(data.messageContent);
                $('#d_date').text(data.date);
                $('#d_avatar').text(data.fullName ? data.fullName.substring(0, 1).toUpperCase() : ""?"");

                if (data.imageUrl && data.imageUrl !== """" && data.imageUrl !== ""/uploads/"") {
                    $('#d_image').attr('src', data.imageUrl).show();
                    // --- الإصلاح هنا: نقوم بتحديث رابط التحميل بمسار الصورة ---
                    $('#d_download').attr('href', data.imageUrl);

                    $('#attachment_container').attr('style', 'displ");
                WriteLiteral(@"ay: block !important');
                    $('#d_no_files').hide();
                } else {
                    $('#attachment_container').hide();
                    $('#d_no_files').show();
                    $('#d_download').attr('href', '#');
                }

                $('#d_reply').attr('href', 'mailto:' + data.email);
                $(`#card-${id}`).find('.msg-card').removeClass('unread-card');
                $(`#icon-${id}`).removeClass('fa-envelope text-primary').addClass('fa-envelope-open text-muted');

                $('#msgDrawer').addClass('open');
                $('#drawerOverlay').fadeIn();
                $('body').css('overflow', 'hidden');
            });
        }

        function closeDrawer() {
            $('#msgDrawer').removeClass('open');
            $('#drawerOverlay').fadeOut();
            $('body').css('overflow', 'auto');
        }
    </script>
